// model_hybrid.rs — Jamba and Falcon-H1 hybrid SSM+Transformer inference pipelines.
//
// Both architectures interleave Mamba-2 SSD layers with standard GQA Transformer layers.
//
//   arch = "jamba"     (ai21labs/AI21-Jamba-1.5-Mini):
//     attn_layer_period = 8 default → layer (l+1) % 8 == 0 is attention
//   arch = "falcon-h1" (tiiuae/Falcon-H1-7B-Reasoning):
//     attn_layer_period = 2 default → every other layer is attention
//
// SSM layer:  rms_norm → in_proj → causal_conv1d → Mamba-2 SSD → out_proj → residual
//             rms_norm → SwiGLU FFN → residual
// Attn layer: rms_norm → Q/K/V proj → RoPE → KV-cache → GQA attention → o_proj → residual
//             rms_norm → SwiGLU FFN → residual
//
// Tensor naming convention (KNOT format):
//   blk_{l}_input_norm_weight       — pre-sublayer RMS norm weight [hidden_dim]
//   blk_{l}_ssm_in_proj_weight      — SSM input projection [d_inner*2, hidden_dim]
//   blk_{l}_ssm_conv1d_weight       — causal conv kernel [d_conv * d_inner]
//   blk_{l}_ssm_conv1d_bias         — conv bias [d_inner]
//   blk_{l}_ssm_a_log               — log diagonal A [d_state]
//   blk_{l}_ssm_dt_bias             — dt bias [d_inner]
//   blk_{l}_ssm_d                   — skip connection [d_inner]
//   blk_{l}_ssm_out_proj_weight     — SSM output projection [hidden_dim, d_inner]
//   blk_{l}_attn_q_weight           — Q projection [n_heads*head_dim, hidden_dim]
//   blk_{l}_attn_k_weight           — K projection [n_kv_heads*head_dim, hidden_dim]
//   blk_{l}_attn_v_weight           — V projection [n_kv_heads*head_dim, hidden_dim]
//   blk_{l}_attn_o_weight           — O projection [hidden_dim, n_heads*head_dim]
//   blk_{l}_ffn_norm_weight         — pre-FFN RMS norm weight [hidden_dim]
//   blk_{l}_ffn_gate_weight         — SwiGLU gate [intermediate_size, hidden_dim]
//   blk_{l}_ffn_up_weight           — SwiGLU up [intermediate_size, hidden_dim]
//   blk_{l}_ffn_down_weight         — SwiGLU down [hidden_dim, intermediate_size]

use crate::loader::{KnotConfig, WeightBackend};
use crate::math::f16_to_f32;
use std::sync::Arc;

// ─────────────────────────────────────────────────────────────────────────────
// Config
// ─────────────────────────────────────────────────────────────────────────────

#[derive(Clone, Debug)]
pub struct HybridConfig {
    pub arch: String,
    pub hidden_dim: usize,
    pub num_layers: usize,
    pub vocab_size: usize,
    // Attention
    pub n_heads: usize,
    pub n_kv_heads: usize,
    pub head_dim: usize,
    pub rope_theta: f32,
    pub max_seq_len: usize,
    // FFN
    pub intermediate_size: usize,
    // SSM (Mamba-1 S6 for Jamba; Mamba-2 SSD for Falcon-H1)
    pub d_state: usize,
    pub d_conv: usize,
    pub d_inner: usize,
    /// dt projection rank for the Mamba-1 S6 kernel (Jamba = 256). None ⇒
    /// Mamba-2 SSD path (Falcon-H1). When the knot config omits the field
    /// (the Jamba encoder does), it is derived from the `ssm_dt_proj_weight`
    /// shape at load time: `dt_rank = numel(dt_proj) / d_inner`.
    pub dt_rank: Option<usize>,
    // MoE
    /// Number of experts in sparse FFN layers (Jamba = 16). 0 ⇒ no MoE.
    pub num_experts: usize,
    /// Top-k experts per token (Jamba = 2).
    pub num_experts_per_tok: usize,
    // Hybrid layout
    pub attn_layer_period: usize,
    pub attn_layer_offset: usize,
    pub expert_layer_period: usize,
    pub expert_layer_offset: usize,
    pub rms_norm_eps: f32,
}

impl HybridConfig {
    pub fn from_knot(k: &KnotConfig) -> Self {
        let expand = k.ssm_expand.unwrap_or(2);
        // HF Jamba: a layer is `attention` iff `i % attn_layer_period == attn_layer_offset`;
        // otherwise it is a `mamba` (SSM) layer. Jamba-1.5: period 8, offset 4
        // (attention at layers 4, 12, 20, 28). Falcon-H1: period 2, offset 1.
        let (attn_period, attn_offset) = match k.arch.as_str() {
            "jamba" => (k.hybrid_attn_layer_period.unwrap_or(8), 4),
            "falcon-h1" => (k.hybrid_attn_layer_period.unwrap_or(2), 1),
            _ => (k.hybrid_attn_layer_period.unwrap_or(4), 0),
        };
        // HF Jamba: a layer's FFN is MoE iff `i % expert_layer_period == expert_layer_offset`.
        // Jamba-1.5: period 2, offset 1 (MoE on odd layers 1,3,...,31; dense on even).
        let (expert_period, expert_offset) = match k.arch.as_str() {
            "jamba" => (2, 1),
            _ => (1, 0), // Falcon-H1 has no MoE: period 1, offset 0 ⇒ never MoE (offset must be < period)
        };
        let num_experts = k.num_experts.unwrap_or(match k.arch.as_str() {
            "jamba" => 16,
            _ => 0,
        });
        let top_k = k.num_experts_per_tok.unwrap_or(2);
        Self {
            arch: k.arch.clone(),
            hidden_dim: k.hidden_dim,
            num_layers: k.num_layers,
            vocab_size: k.vocab_size,
            n_heads: k.num_heads,
            n_kv_heads: k.num_kv_heads,
            head_dim: k.head_dim,
            rope_theta: k.rope_theta,
            max_seq_len: k.max_seq_len.unwrap_or(2048),
            intermediate_size: k.intermediate_size,
            d_state: k.d_state.unwrap_or(16),
            d_conv: k.d_conv.unwrap_or(4),
            d_inner: k.hidden_dim * expand,
            dt_rank: k.dt_rank,
            num_experts,
            num_experts_per_tok: top_k,
            attn_layer_period: attn_period,
            attn_layer_offset: attn_offset,
            expert_layer_period: expert_period,
            expert_layer_offset: expert_offset,
            rms_norm_eps: k.rms_norm_eps,
        }
    }

    /// True iff layer `l` is a Transformer attention block (else a Mamba SSM block).
    /// Mirrors HF `JambaConfig.layers_block_type`:
    ///   `attention` iff `l % attn_layer_period == attn_layer_offset`.
    #[inline]
    pub fn is_attn_layer(&self, l: usize) -> bool {
        self.attn_layer_period > 0 && l % self.attn_layer_period == self.attn_layer_offset
    }

    /// True iff layer `l`'s FFN is a sparse MoE block (else a dense SwiGLU FFN).
    /// Mirrors HF `JambaConfig.layers_num_experts`:
    ///   MoE iff `num_experts > 1 && l % expert_layer_period == expert_layer_offset`.
    #[inline]
    pub fn is_moe_layer(&self, l: usize) -> bool {
        self.num_experts > 1
            && self.expert_layer_period > 0
            && self.expert_layer_offset < self.expert_layer_period
            && l % self.expert_layer_period == self.expert_layer_offset
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Per-layer recurrent / KV state
// ─────────────────────────────────────────────────────────────────────────────

pub enum HybridLayerState {
    Mamba {
        conv_buf: Vec<f32>, // [(d_conv-1) * d_inner]
        ssm_h: Vec<f32>,    // [d_state] — Mamba-2 diagonal A state
    },
    Attn {
        k_cache: Vec<f32>, // [max_seq_len * n_kv_heads * head_dim]
        v_cache: Vec<f32>, // [max_seq_len * n_kv_heads * head_dim]
        pos: usize,
    },
}

impl HybridLayerState {
    /// `ssm_state_len` is `d_inner * d_state` for the Mamba-1 S6 path (Jamba,
    /// per-channel state) and `d_state` for the Mamba-2 SSD fallback (Falcon-H1).
    fn new_mamba(d_inner: usize, d_conv: usize, ssm_state_len: usize) -> Self {
        Self::Mamba {
            conv_buf: vec![0.0; (d_conv - 1) * d_inner],
            ssm_h: vec![0.0; ssm_state_len],
        }
    }

    fn new_attn(max_seq_len: usize, n_kv_heads: usize, head_dim: usize) -> Self {
        let kv_size = max_seq_len * n_kv_heads * head_dim;
        Self::Attn {
            k_cache: vec![0.0; kv_size],
            v_cache: vec![0.0; kv_size],
            pos: 0,
        }
    }

    pub fn reset(&mut self) {
        match self {
            Self::Mamba { conv_buf, ssm_h } => {
                conv_buf.fill(0.0);
                ssm_h.fill(0.0);
            }
            Self::Attn {
                k_cache,
                v_cache,
                pos,
            } => {
                k_cache.fill(0.0);
                v_cache.fill(0.0);
                *pos = 0;
            }
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Per-layer weights
// ─────────────────────────────────────────────────────────────────────────────

/// A single expert's SwiGLU weights.
pub struct Expert {
    gate: Vec<f32>, // [intermediate_size, hidden_dim]
    up: Vec<f32>,   // [intermediate_size, hidden_dim]
    down: Vec<f32>, // [hidden_dim, intermediate_size]
}

/// Per-layer FFN: a dense SwiGLU (Jamba even layers / Falcon-H1) or a
/// top-k sparse mixture-of-experts (Jamba odd layers).
pub enum HybridFfn {
    Dense {
        gate: Vec<f32>,
        up: Vec<f32>,
        down: Vec<f32>,
    },
    Moe {
        router: Vec<f32>, // [num_experts, hidden_dim]
        experts: Vec<Expert>,
    },
}

pub enum HybridLayerWeights {
    Mamba {
        input_norm: Vec<f32>,
        in_proj: Vec<f32>,
        conv1d_w: Vec<f32>,
        conv1d_b: Vec<f32>,
        // Mamba-1 S6 selective projections (Jamba). For the Mamba-2 SSD fallback
        // (Falcon-H1) these are empty and the SSD path keys off `dt_rank == None`.
        x_proj: Vec<f32>,    // [dt_rank + 2*d_state, d_inner]
        dt_proj: Vec<f32>,   // [d_inner, dt_rank]
        dt_proj_b: Vec<f32>, // [d_inner]
        // Jamba SSM RMSNorms applied to dt / B / C after the x_proj split.
        b_norm: Vec<f32>,  // [d_state]
        c_norm: Vec<f32>,  // [d_state]
        dt_norm: Vec<f32>, // [dt_rank]
        a_log: Vec<f32>,   // S6: [d_inner * d_state]; SSD fallback: [d_state]
        dt_bias: Vec<f32>, // SSD-only dt bias [d_inner] (Mamba-2 fallback)
        d_skip: Vec<f32>,  // [d_inner]
        out_proj: Vec<f32>,
        ffn_norm: Vec<f32>,
        ffn: HybridFfn,
    },
    Attn {
        input_norm: Vec<f32>,
        q_w: Vec<f32>,
        k_w: Vec<f32>,
        v_w: Vec<f32>,
        o_w: Vec<f32>,
        ffn_norm: Vec<f32>,
        ffn: HybridFfn,
    },
}

// ─────────────────────────────────────────────────────────────────────────────
// Weight helpers
// ─────────────────────────────────────────────────────────────────────────────

fn fetch_f32(backend: &dyn WeightBackend, name: &str) -> Vec<f32> {
    let raw = backend
        .fetch_tensor(name)
        .unwrap_or_else(|_| panic!("Hybrid: missing tensor {name}"));
    let mut out = vec![0.0f32; raw.len() / 4];
    for (i, chunk) in raw.chunks_exact(4).enumerate() {
        out[i] = f32::from_le_bytes(chunk.try_into().unwrap());
    }
    out
}

fn fetch_or_zeros(backend: &dyn WeightBackend, name: &str, n: usize) -> Vec<f32> {
    if backend.has_tensor(name) {
        fetch_f32(backend, name)
    } else {
        vec![0.0; n]
    }
}

fn fetch_q8(backend: &dyn WeightBackend, name: &str, n_elems: usize) -> Vec<f32> {
    let raw = backend.fetch_tensor(name).expect(name);
    // GGUF Q8_0: 34-byte blocks = 2-byte LE fp16 scale d + 32 int8; x = d * q.
    const BLOCK: usize = 32;
    let mut out = vec![0.0f32; n_elems];
    let mut idx = 0usize;
    for chunk in raw.chunks_exact(2 + BLOCK) {
        let d = f16_to_f32(u16::from_le_bytes([chunk[0], chunk[1]]));
        for (j, &b) in chunk[2..].iter().enumerate() {
            if idx + j >= n_elems {
                break;
            }
            out[idx + j] = (b as i8) as f32 * d;
        }
        idx += BLOCK;
        if idx >= n_elems {
            break;
        }
    }
    out
}

fn fetch_auto(backend: &dyn WeightBackend, name: &str, n_elems: usize) -> Vec<f32> {
    if !backend.has_tensor(name) {
        return vec![0.0; n_elems];
    }
    let is_q8 = backend
        .tensor_info(name)
        .map(|i| i.tensor_type == "Q8_0")
        .unwrap_or(false);
    if is_q8 {
        fetch_q8(backend, name, n_elems)
    } else {
        fetch_f32(backend, name)
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Math kernels
// ─────────────────────────────────────────────────────────────────────────────

#[inline(always)]
fn sigmoid(x: f32) -> f32 {
    1.0 / (1.0 + (-x).exp())
}

#[inline(always)]
fn softplus(x: f32) -> f32 {
    if x > 20.0 {
        x
    } else {
        (1.0 + x.exp()).ln()
    }
}

fn mat_vec(out: &mut [f32], w: &[f32], x: &[f32], rows: usize, cols: usize) {
    assert_eq!(out.len(), rows);
    assert_eq!(x.len(), cols);
    for i in 0..rows {
        let mut s = 0.0f32;
        for j in 0..cols {
            s += w[i * cols + j] * x[j];
        }
        out[i] = s;
    }
}

fn rms_norm(x: &mut [f32], w: &[f32], eps: f32) {
    let ms = x.iter().map(|v| v * v).sum::<f32>() / x.len() as f32;
    let inv = 1.0 / (ms + eps).sqrt();
    for (v, g) in x.iter_mut().zip(w.iter()) {
        *v = *v * inv * g;
    }
}

/// Out-of-place RMSNorm (returns a new Vec). Mirrors HF `JambaRMSNorm`:
/// variance = mean(x^2); x = x / sqrt(variance + eps) * weight (no bias,
/// no mean-centering). Used for the Jamba SSM dt/B/C norms on small vectors.
fn rms_norm_vec(x: &[f32], w: &[f32], eps: f32) -> Vec<f32> {
    let ms = x.iter().map(|v| v * v).sum::<f32>() / x.len() as f32;
    let inv = 1.0 / (ms + eps).sqrt();
    x.iter().zip(w.iter()).map(|(&v, &g)| v * inv * g).collect()
}

/// In-place RoPE for packed [n_heads * head_dim] vector at position `pos`.
fn rope_apply(x: &mut [f32], pos: usize, head_dim: usize, rope_theta: f32) {
    let n_heads = x.len() / head_dim;
    for h in 0..n_heads {
        let off = h * head_dim;
        for i in 0..head_dim / 2 {
            let theta = (pos as f32) * rope_theta.powf(-2.0 * i as f32 / head_dim as f32);
            let (sin_t, cos_t) = theta.sin_cos();
            let x0 = x[off + 2 * i];
            let x1 = x[off + 2 * i + 1];
            x[off + 2 * i] = x0 * cos_t - x1 * sin_t;
            x[off + 2 * i + 1] = x0 * sin_t + x1 * cos_t;
        }
    }
}

fn softmax_inplace(x: &mut [f32]) {
    let max = x.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    let mut sum = 0.0f32;
    for v in x.iter_mut() {
        *v = (*v - max).exp();
        sum += *v;
    }
    for v in x.iter_mut() {
        *v /= sum;
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Mamba-2 SSD step (inline, same math as model_mamba.rs mamba2_ssd_step)
// ─────────────────────────────────────────────────────────────────────────────

// Causal depthwise conv1d step. Mirrors the FIXED `model_mamba.rs`
// `causal_conv1d_step`:
//   * convolve over the full window [t-(d_conv-1) .. t] BEFORE mutating the
//     rolling history (shifting x_new in first double-counts it), and
//   * use the HF depthwise weight layout `weight[ch * d_conv + k]`
//     (channel-major, kernel contiguous per channel) — NOT kernel-major.
// SiLU is applied after the conv (HF applies `act` once after conv).
fn hybrid_causal_conv1d_step(
    out: &mut [f32],
    x_new: &[f32],
    conv_buf: &mut [f32],
    weight: &[f32],
    bias: &[f32],
    d_inner: usize,
    d_conv: usize,
) {
    let hist_len = d_conv - 1;
    for ch in 0..d_inner {
        let mut s = 0.0f32;
        // history positions 0..hist_len (oldest first)
        for k in 0..hist_len {
            s += conv_buf[k * d_inner + ch] * weight[ch * d_conv + k];
        }
        // current token at kernel slot d_conv-1
        s += x_new[ch] * weight[ch * d_conv + (d_conv - 1)];
        let b = if bias.len() == d_inner { bias[ch] } else { 0.0 };
        let v = s + b;
        out[ch] = v * sigmoid(v); // SiLU
    }
    // advance rolling history: shift [1..] → [0..hist_len-1], write x_new newest
    conv_buf.copy_within(d_inner.., 0);
    conv_buf[(hist_len - 1) * d_inner..].copy_from_slice(x_new);
}

fn hybrid_mamba2_ssd_step(
    y: &mut [f32],
    x_conv: &[f32],
    h: &mut [f32],
    a_log: &[f32],
    dt_bias: &[f32],
    d_skip: &[f32],
    d_inner: usize,
    d_state: usize,
) {
    let b_slice = &x_conv[..d_state.min(d_inner)];
    let c_slice = &x_conv[d_state.min(d_inner)..2 * d_state.min(d_inner)];

    let dt_scalar: f32 = if !dt_bias.is_empty() {
        dt_bias.iter().map(|&v| softplus(v)).sum::<f32>() / dt_bias.len() as f32
    } else {
        1.0
    };

    for s in 0..d_state {
        let a = (dt_scalar * a_log[s]).exp();
        let b_s = if s < b_slice.len() { b_slice[s] } else { 0.0 };
        let x_s: f32 = x_conv.iter().sum::<f32>() / d_inner as f32;
        h[s] = h[s] * a + dt_scalar * b_s * x_s;
    }

    let c_mean: f32 = if !c_slice.is_empty() {
        c_slice.iter().sum::<f32>() / c_slice.len() as f32
    } else {
        1.0
    };
    let h_sum: f32 = h.iter().sum::<f32>();

    for ch in 0..d_inner {
        let g = x_conv[ch] * sigmoid(x_conv[ch]); // SiLU
        y[ch] = (c_mean * h_sum * x_conv[ch] + d_skip[ch] * x_conv[ch]) * g;
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Jamba Mamba-1 S6 step with dt/B/C RMSNorms (single token).
//
// Faithful port of HF `JambaMambaMixer.slow_forward` (the input-dependent S6
// selective scan), adding the three Jamba-only RMSNorms that vanilla Mamba-1
// lacks. Verified element-wise against numpy (/tmp/jamba_ref.py):
//
//   ssm_params = x_proj(x_conv)                  # [dt_rank + 2*d_state]
//   dt, B, C   = split(ssm_params, dt_rank, d_state, d_state)
//   dt = dt_layernorm(dt);  B = b_layernorm(B);  C = c_layernorm(C)   # RMSNorm
//   dt = softplus(dt_proj @ dt + dt_proj_bias)   # [d_inner]
//   A  = -exp(a_log)                             # [d_inner, d_state]
//   h[ch,s] = h[ch,s] * exp(dt[ch]*A[ch,s]) + dt[ch]*B[s]*x_conv[ch]
//   y[ch]   = Σ_s C[s]*h[ch,s] + D[ch]*x_conv[ch]
//
// The caller applies the SiLU(gate) afterwards (matching HF
// `scan_output * act(gate)`), so this returns the *un-gated* scan output.
#[allow(clippy::too_many_arguments)]
fn hybrid_jamba_s6_step(
    y: &mut [f32],
    x_conv: &[f32],    // [d_inner] — post-conv SiLU output (the SSM input)
    h: &mut [f32],     // [d_inner * d_state] — per-channel recurrent state
    x_proj_w: &[f32],  // [dt_rank + 2*d_state, d_inner]
    dt_proj_w: &[f32], // [d_inner, dt_rank]
    dt_proj_b: &[f32], // [d_inner]
    b_norm: &[f32],    // [d_state]
    c_norm: &[f32],    // [d_state]
    dt_norm: &[f32],   // [dt_rank]
    a_log: &[f32],     // [d_inner * d_state]
    d_skip: &[f32],    // [d_inner]
    d_inner: usize,
    d_state: usize,
    dt_rank: usize,
    eps: f32,
) {
    // x_proj → [dt_rank, B(d_state), C(d_state)]
    let xp_rows = dt_rank + 2 * d_state;
    let mut xp = vec![0.0f32; xp_rows];
    mat_vec(&mut xp, x_proj_w, x_conv, xp_rows, d_inner);

    // Jamba RMSNorms on dt / B / C right after the split (no bias).
    let dt_normed = rms_norm_vec(&xp[0..dt_rank], dt_norm, eps);
    let b_vec = rms_norm_vec(&xp[dt_rank..dt_rank + d_state], b_norm, eps);
    let c_vec = rms_norm_vec(&xp[dt_rank + d_state..], c_norm, eps);

    // dt = softplus(dt_proj @ dt_normed + dt_bias)
    let mut dt = vec![0.0f32; d_inner];
    mat_vec(&mut dt, dt_proj_w, &dt_normed, d_inner, dt_rank);
    for (v, &b) in dt.iter_mut().zip(dt_proj_b.iter()) {
        *v = softplus(*v + b);
    }

    // Selective scan per channel. A = -exp(a_log); Abar = exp(dt*A) ∈ (0,1).
    for ch in 0..d_inner {
        let dt_ch = dt[ch];
        let mut yi = d_skip[ch] * x_conv[ch];
        for s in 0..d_state {
            let idx = ch * d_state + s;
            let a = (-dt_ch * a_log[idx].exp()).exp(); // exp(dt * -exp(a_log))
            h[idx] = h[idx] * a + dt_ch * b_vec[s] * x_conv[ch];
            yi += c_vec[s] * h[idx];
        }
        y[ch] = yi;
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Jamba sparse MoE block (top-k, no renormalization).
//
// Faithful port of HF `JambaSparseMoeBlock.forward` +
// `route_tokens_to_experts`. Verified against numpy (/tmp/jamba_ref.py):
//
//   router_logits = router @ x                       # [num_experts]
//   routing_w     = softmax(router_logits)           # over ALL experts
//   top_w, top_i  = topk(routing_w, top_k)           # NOT renormalized (HF)
//   out = Σ_{e in top_i} top_w[e] * down_e(silu(gate_e(x)) * up_e(x))
//
// NOTE: Jamba — unlike Mixtral — does NOT renormalize the top-k weights. The
// selected softmax probabilities are used as-is (they sum to < 1.0). This is
// the behavior of HF transformers v4.40 → v5.5.x; see report.
fn jamba_moe_block(
    x: &[f32],
    router: &[f32], // [num_experts, hidden_dim]
    experts: &[Expert],
    hidden_dim: usize,
    intermediate_size: usize,
    top_k: usize,
) -> Vec<f32> {
    let num_experts = experts.len();
    // Router logits then full softmax over all experts.
    let mut logits = vec![0.0f32; num_experts];
    mat_vec(&mut logits, router, x, num_experts, hidden_dim);
    let mut probs = logits.clone();
    softmax_inplace(&mut probs);

    // Top-k selection by probability (partial selection sort over k).
    let k = top_k.min(num_experts);
    let mut chosen: Vec<usize> = Vec::with_capacity(k);
    let mut used = vec![false; num_experts];
    for _ in 0..k {
        let mut best = usize::MAX;
        let mut best_p = f32::NEG_INFINITY;
        for (e, &p) in probs.iter().enumerate() {
            if !used[e] && p > best_p {
                best_p = p;
                best = e;
            }
        }
        if best == usize::MAX {
            break;
        }
        used[best] = true;
        chosen.push(best);
    }

    // Weighted sum of the chosen experts' SwiGLU outputs (no renormalization).
    let mut out = vec![0.0f32; hidden_dim];
    for &e in &chosen {
        let w = probs[e];
        let ex = &experts[e];
        let ey = swiglu_ffn(x, &ex.gate, &ex.up, &ex.down, hidden_dim, intermediate_size);
        for i in 0..hidden_dim {
            out[i] += w * ey[i];
        }
    }
    out
}

/// Apply a layer's FFN (dense SwiGLU or sparse MoE) to a pre-normed input.
fn apply_ffn(
    ffn: &HybridFfn,
    normed: &[f32],
    hidden_dim: usize,
    intermediate_size: usize,
    top_k: usize,
) -> Vec<f32> {
    match ffn {
        HybridFfn::Dense { gate, up, down } => {
            swiglu_ffn(normed, gate, up, down, hidden_dim, intermediate_size)
        }
        HybridFfn::Moe { router, experts } => jamba_moe_block(
            normed,
            router,
            experts,
            hidden_dim,
            intermediate_size,
            top_k,
        ),
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// GQA attention step (with KV cache, RoPE already applied to q and k_new)
// ─────────────────────────────────────────────────────────────────────────────

fn gqa_attention_step(
    out: &mut [f32],     // [n_heads * head_dim]
    q: &[f32],           // [n_heads * head_dim]
    k_cache: &mut [f32], // [max_seq_len * n_kv_heads * head_dim]
    v_cache: &mut [f32], // [max_seq_len * n_kv_heads * head_dim]
    k_new: &[f32],       // [n_kv_heads * head_dim]
    v_new: &[f32],       // [n_kv_heads * head_dim]
    pos: usize,
    n_heads: usize,
    n_kv_heads: usize,
    head_dim: usize,
) {
    let kv_head_stride = n_kv_heads * head_dim;
    // Store new K and V
    k_cache[pos * kv_head_stride..(pos + 1) * kv_head_stride].copy_from_slice(k_new);
    v_cache[pos * kv_head_stride..(pos + 1) * kv_head_stride].copy_from_slice(v_new);

    let seq_len = pos + 1;
    let kv_per_q = (n_heads / n_kv_heads).max(1);
    let scale = 1.0 / (head_dim as f32).sqrt();

    for h in 0..n_heads {
        let kv_h = h / kv_per_q;
        let q_off = h * head_dim;

        // Compute scores against all cached K positions
        let mut scores = vec![0.0f32; seq_len];
        for t in 0..seq_len {
            let k_off = t * kv_head_stride + kv_h * head_dim;
            let mut dot = 0.0f32;
            for i in 0..head_dim {
                dot += q[q_off + i] * k_cache[k_off + i];
            }
            scores[t] = dot * scale;
        }
        softmax_inplace(&mut scores);

        // Weighted sum of V
        let out_off = h * head_dim;
        out[out_off..out_off + head_dim].fill(0.0);
        for t in 0..seq_len {
            let v_off = t * kv_head_stride + kv_h * head_dim;
            for i in 0..head_dim {
                out[out_off + i] += scores[t] * v_cache[v_off + i];
            }
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// SwiGLU FFN
// ─────────────────────────────────────────────────────────────────────────────

fn swiglu_ffn(
    x: &[f32],
    gate_w: &[f32],
    up_w: &[f32],
    down_w: &[f32],
    hidden_dim: usize,
    intermediate_size: usize,
) -> Vec<f32> {
    let mut gate = vec![0.0f32; intermediate_size];
    let mut up = vec![0.0f32; intermediate_size];
    mat_vec(&mut gate, gate_w, x, intermediate_size, hidden_dim);
    mat_vec(&mut up, up_w, x, intermediate_size, hidden_dim);
    // SiLU(gate) * up
    for i in 0..intermediate_size {
        gate[i] = gate[i] * sigmoid(gate[i]) * up[i];
    }
    let mut out = vec![0.0f32; hidden_dim];
    mat_vec(&mut out, down_w, &gate, hidden_dim, intermediate_size);
    out
}

// ─────────────────────────────────────────────────────────────────────────────
// HybridPipeline
// ─────────────────────────────────────────────────────────────────────────────

pub struct HybridPipeline {
    pub config: HybridConfig,
    layers: Vec<HybridLayerWeights>,
    pub states: Vec<HybridLayerState>,
    token_embd: Vec<f32>,  // [vocab_size * hidden_dim]
    output_norm: Vec<f32>, // [hidden_dim]
    lm_head: Vec<f32>,     // [vocab_size * hidden_dim]
    seq_pos: usize,        // global token position for RoPE
}

impl HybridPipeline {
    pub fn from_knot(knot_cfg: &KnotConfig, backend: Arc<dyn WeightBackend>) -> Self {
        let cfg = HybridConfig::from_knot(knot_cfg);
        let d = cfg.hidden_dim;
        let di = cfg.d_inner;
        let fi = cfg.intermediate_size;
        let nh = cfg.n_heads;
        let nkv = cfg.n_kv_heads;
        let hd = cfg.head_dim;

        let token_embd = fetch_auto(&*backend, "token_embd_weight", cfg.vocab_size * d);
        let output_norm = fetch_or_zeros(&*backend, "output_norm_weight", d);
        // Tied-embedding fallback (see model_mamba.rs / model_rwkv7.rs): when the
        // knot has no separate output projection, reuse token_embd as lm_head
        // instead of letting fetch_auto return all-zeros (-> dead logits).
        let lm_head = if backend.has_tensor("output_weight") {
            fetch_auto(&*backend, "output_weight", cfg.vocab_size * d)
        } else {
            token_embd.clone()
        };

        // dt_rank: the Jamba encoder omits it from the knot config. Derive it from
        // the first Mamba layer's `ssm_dt_proj_weight` shape (`[d_inner, dt_rank]`):
        // dt_rank = numel(dt_proj) / d_inner. The dt_proj length comes from the
        // knot header (TensorInfo.length / bytes_per_elem); for fp32 that's len/4.
        // Falcon-H1 has no dt_proj ⇒ dt_rank stays None ⇒ Mamba-2 SSD fallback.
        let derived_dt_rank: Option<usize> = cfg.dt_rank.or_else(|| {
            // Find the lowest layer that is a Mamba layer carrying a dt_proj tensor.
            (0..cfg.num_layers).find_map(|l| {
                let name = format!("blk_{l}_ssm_dt_proj_weight");
                if !backend.has_tensor(&name) {
                    return None;
                }
                // Prefer deriving dt_rank from the dt_proj shape via tensor_info.
                if let Some(info) = backend.tensor_info(&name) {
                    // bytes → elements: Q8_0 blocks are 34 B / 32 elems; fp32 = 4 B.
                    let n_elems = if info.tensor_type == "Q8_0" {
                        (info.length as usize / 34) * 32
                    } else {
                        info.length as usize / 4
                    };
                    return Some((n_elems / di).max(1));
                }
                // tensor_info unavailable (e.g. a backend that doesn't expose
                // metadata). The dt_proj tensor IS present, so this is an S6
                // Jamba layer — fall back to HF Jamba's default dt_rank = 256
                // (`mamba_dt_rank`). Other future S6 hybrids should set dt_rank
                // explicitly in the knot config.
                if cfg.arch == "jamba" {
                    Some(256)
                } else {
                    None
                }
            })
        });

        // Resolve effective num_experts: trust the config, else count the
        // `blk_{first_moe}_expert_{e}_*` tensors actually present in the knot.
        let effective_num_experts = if cfg.num_experts > 0 {
            cfg.num_experts
        } else {
            // Find the first MoE-eligible layer and count its experts.
            (0..cfg.num_layers)
                .filter(|&l| backend.has_tensor(&format!("blk_{l}_moe_router_weight")))
                .map(|l| {
                    let mut e = 0;
                    while backend.has_tensor(&format!("blk_{l}_expert_{e}_gate_weight")) {
                        e += 1;
                    }
                    e
                })
                .find(|&e| e > 0)
                .unwrap_or(0)
        };
        let mut cfg = cfg;
        cfg.dt_rank = derived_dt_rank;
        cfg.num_experts = effective_num_experts;

        let mut layers = Vec::with_capacity(cfg.num_layers);
        let mut states = Vec::with_capacity(cfg.num_layers);

        for l in 0..cfg.num_layers {
            let n = |s: &str| format!("blk_{l}_{s}");
            let input_norm = fetch_or_zeros(&*backend, &n("input_norm_weight"), d);
            let ffn_norm = fetch_or_zeros(&*backend, &n("ffn_norm_weight"), d);

            // FFN: MoE (sparse) on expert layers, dense SwiGLU otherwise.
            // Use the actual router-tensor presence as the authority so a knot
            // whose layout differs from the offset heuristic still loads right.
            let has_router = backend.has_tensor(&n("moe_router_weight"));
            let ffn = if has_router || (cfg.is_moe_layer(l) && cfg.num_experts > 1) {
                let ne = cfg.num_experts;
                let router = fetch_auto(&*backend, &n("moe_router_weight"), ne * d);
                let mut experts = Vec::with_capacity(ne);
                for e in 0..ne {
                    experts.push(Expert {
                        gate: fetch_auto(&*backend, &n(&format!("expert_{e}_gate_weight")), fi * d),
                        up: fetch_auto(&*backend, &n(&format!("expert_{e}_up_weight")), fi * d),
                        down: fetch_auto(&*backend, &n(&format!("expert_{e}_down_weight")), d * fi),
                    });
                }
                HybridFfn::Moe { router, experts }
            } else {
                HybridFfn::Dense {
                    gate: fetch_auto(&*backend, &n("ffn_gate_weight"), fi * d),
                    up: fetch_auto(&*backend, &n("ffn_up_weight"), fi * d),
                    down: fetch_auto(&*backend, &n("ffn_down_weight"), d * fi),
                }
            };

            if cfg.is_attn_layer(l) {
                layers.push(HybridLayerWeights::Attn {
                    input_norm,
                    q_w: fetch_auto(&*backend, &n("attn_q_weight"), nh * hd * d),
                    k_w: fetch_auto(&*backend, &n("attn_k_weight"), nkv * hd * d),
                    v_w: fetch_auto(&*backend, &n("attn_v_weight"), nkv * hd * d),
                    o_w: fetch_auto(&*backend, &n("attn_o_weight"), d * nh * hd),
                    ffn_norm,
                    ffn,
                });
                states.push(HybridLayerState::new_attn(cfg.max_seq_len, nkv, hd));
            } else {
                // S6 (Jamba) iff dt_rank known AND the layer has an x_proj tensor.
                let is_s6 = cfg.dt_rank.is_some() && backend.has_tensor(&n("ssm_x_proj_weight"));
                let dt_rank = cfg.dt_rank.unwrap_or(0);
                // a_log: S6 is per-channel [d_inner * d_state]; SSD is [d_state].
                let a_log_len = if is_s6 { di * cfg.d_state } else { cfg.d_state };
                layers.push(HybridLayerWeights::Mamba {
                    input_norm,
                    in_proj: fetch_auto(&*backend, &n("ssm_in_proj_weight"), di * 2 * d),
                    conv1d_w: fetch_auto(&*backend, &n("ssm_conv1d_weight"), cfg.d_conv * di),
                    conv1d_b: fetch_or_zeros(&*backend, &n("ssm_conv1d_bias"), di),
                    x_proj: if is_s6 {
                        fetch_auto(
                            &*backend,
                            &n("ssm_x_proj_weight"),
                            (dt_rank + 2 * cfg.d_state) * di,
                        )
                    } else {
                        Vec::new()
                    },
                    dt_proj: if is_s6 {
                        fetch_auto(&*backend, &n("ssm_dt_proj_weight"), di * dt_rank)
                    } else {
                        Vec::new()
                    },
                    dt_proj_b: if is_s6 {
                        fetch_or_zeros(&*backend, &n("ssm_dt_proj_bias"), di)
                    } else {
                        Vec::new()
                    },
                    b_norm: if is_s6 {
                        fetch_or_zeros(&*backend, &n("ssm_b_norm_weight"), cfg.d_state)
                    } else {
                        Vec::new()
                    },
                    c_norm: if is_s6 {
                        fetch_or_zeros(&*backend, &n("ssm_c_norm_weight"), cfg.d_state)
                    } else {
                        Vec::new()
                    },
                    dt_norm: if is_s6 {
                        fetch_or_zeros(&*backend, &n("ssm_dt_norm_weight"), dt_rank)
                    } else {
                        Vec::new()
                    },
                    a_log: fetch_or_zeros(&*backend, &n("ssm_a_log"), a_log_len),
                    dt_bias: fetch_or_zeros(&*backend, &n("ssm_dt_bias"), di),
                    d_skip: fetch_or_zeros(&*backend, &n("ssm_d"), di),
                    out_proj: fetch_auto(&*backend, &n("ssm_out_proj_weight"), d * di),
                    ffn_norm,
                    ffn,
                });
                let ssm_state_len = if is_s6 { di * cfg.d_state } else { cfg.d_state };
                states.push(HybridLayerState::new_mamba(di, cfg.d_conv, ssm_state_len));
            }
        }

        Self {
            config: cfg,
            layers,
            states,
            token_embd,
            output_norm,
            lm_head,
            seq_pos: 0,
        }
    }

    pub fn reset_states(&mut self) {
        for s in &mut self.states {
            s.reset();
        }
        self.seq_pos = 0;
    }

    /// Global token position used for RoPE on the attention sublayers. Part of
    /// the resumable state: a checkpoint must carry it so a restore into a fresh
    /// pipeline applies RoPE at the correct positions.
    #[inline]
    pub fn seq_pos(&self) -> usize {
        self.seq_pos
    }

    /// Restore the global RoPE position (paired with restoring per-layer state).
    #[inline]
    pub fn set_seq_pos(&mut self, pos: usize) {
        self.seq_pos = pos;
    }

    pub fn forward_one(&mut self, token_id: u32, logits: &mut [f32]) {
        let cfg = &self.config;
        let d = cfg.hidden_dim;
        let di = cfg.d_inner;
        let top_k = cfg.num_experts_per_tok;
        let tok = token_id as usize;
        let pos = self.seq_pos;

        // Embed
        let mut x = self.token_embd[tok * d..(tok + 1) * d].to_vec();

        for l in 0..cfg.num_layers {
            // borrow split: separate layers and states
            let (layer_slice, state_slice) = (&self.layers[l..], &mut self.states[l..]);
            let layer = &layer_slice[0];
            let state = &mut state_slice[0];

            match (layer, state) {
                (
                    HybridLayerWeights::Mamba {
                        input_norm,
                        in_proj,
                        conv1d_w,
                        conv1d_b,
                        x_proj,
                        dt_proj,
                        dt_proj_b,
                        b_norm,
                        c_norm,
                        dt_norm,
                        a_log,
                        dt_bias,
                        d_skip,
                        out_proj,
                        ffn_norm,
                        ffn,
                    },
                    HybridLayerState::Mamba { conv_buf, ssm_h },
                ) => {
                    // Pre-norm
                    let mut normed = x.clone();
                    rms_norm(&mut normed, input_norm, cfg.rms_norm_eps);

                    // in_proj: [2*d_inner, hidden_dim] → split (ssm input xz, gate)
                    let mut proj = vec![0.0f32; di * 2];
                    mat_vec(&mut proj, in_proj, &normed, di * 2, d);
                    let xz = proj[..di].to_vec();
                    let gate = proj[di..].to_vec();

                    // Causal conv1d + SiLU
                    let mut conv_out = vec![0.0f32; di];
                    hybrid_causal_conv1d_step(
                        &mut conv_out,
                        &xz,
                        conv_buf,
                        conv1d_w,
                        conv1d_b,
                        di,
                        cfg.d_conv,
                    );

                    // SSM step: Jamba Mamba-1 S6 (with dt/B/C norms) when dt_rank
                    // is known and x_proj is present; else the Mamba-2 SSD fallback.
                    let mut y = vec![0.0f32; di];
                    if let Some(dt_rank) = cfg.dt_rank {
                        if !x_proj.is_empty() {
                            hybrid_jamba_s6_step(
                                &mut y,
                                &conv_out,
                                ssm_h,
                                x_proj,
                                dt_proj,
                                dt_proj_b,
                                b_norm,
                                c_norm,
                                dt_norm,
                                a_log,
                                d_skip,
                                di,
                                cfg.d_state,
                                dt_rank,
                                cfg.rms_norm_eps,
                            );
                            // HF: scan_output * act(gate). Gate with SiLU(z).
                            for i in 0..di {
                                y[i] *= gate[i] * sigmoid(gate[i]);
                            }
                        } else {
                            // dt_rank known but this layer lacks x_proj — SSD fallback.
                            let mut gate_copy = gate.clone();
                            for v in &mut gate_copy {
                                *v = *v * sigmoid(*v);
                            }
                            hybrid_mamba2_ssd_step(
                                &mut y,
                                &conv_out,
                                ssm_h,
                                a_log,
                                dt_bias,
                                d_skip,
                                di,
                                cfg.d_state,
                            );
                            for i in 0..di {
                                y[i] *= gate_copy[i];
                            }
                        }
                    } else {
                        // Mamba-2 SSD (Falcon-H1)
                        let mut gate_copy = gate.clone();
                        for v in &mut gate_copy {
                            *v = *v * sigmoid(*v);
                        }
                        hybrid_mamba2_ssd_step(
                            &mut y,
                            &conv_out,
                            ssm_h,
                            a_log,
                            dt_bias,
                            d_skip,
                            di,
                            cfg.d_state,
                        );
                        for i in 0..di {
                            y[i] *= gate_copy[i];
                        }
                    }

                    // out_proj
                    let mut delta = vec![0.0f32; d];
                    mat_vec(&mut delta, out_proj, &y, d, di);
                    for i in 0..d {
                        x[i] += delta[i];
                    }

                    // FFN sublayer (dense SwiGLU or sparse MoE)
                    let mut normed2 = x.clone();
                    rms_norm(&mut normed2, ffn_norm, cfg.rms_norm_eps);
                    let ffn_out = apply_ffn(ffn, &normed2, d, cfg.intermediate_size, top_k);
                    for i in 0..d {
                        x[i] += ffn_out[i];
                    }
                }

                (
                    HybridLayerWeights::Attn {
                        input_norm,
                        q_w,
                        k_w,
                        v_w,
                        o_w,
                        ffn_norm,
                        ffn,
                    },
                    HybridLayerState::Attn {
                        k_cache,
                        v_cache,
                        pos: attn_pos,
                    },
                ) => {
                    // Pre-norm
                    let mut normed = x.clone();
                    rms_norm(&mut normed, input_norm, cfg.rms_norm_eps);

                    // Q, K, V projections
                    let qd = cfg.n_heads * cfg.head_dim;
                    let kd = cfg.n_kv_heads * cfg.head_dim;

                    let mut q = vec![0.0f32; qd];
                    let mut k = vec![0.0f32; kd];
                    let mut v = vec![0.0f32; kd];
                    mat_vec(&mut q, q_w, &normed, qd, d);
                    mat_vec(&mut k, k_w, &normed, kd, d);
                    mat_vec(&mut v, v_w, &normed, kd, d);

                    // RoPE on Q and K
                    rope_apply(&mut q, pos, cfg.head_dim, cfg.rope_theta);
                    rope_apply(&mut k, pos, cfg.head_dim, cfg.rope_theta);

                    // GQA attention with KV cache
                    let mut attn_out = vec![0.0f32; qd];
                    gqa_attention_step(
                        &mut attn_out,
                        &q,
                        k_cache,
                        v_cache,
                        &k,
                        &v,
                        *attn_pos,
                        cfg.n_heads,
                        cfg.n_kv_heads,
                        cfg.head_dim,
                    );
                    *attn_pos += 1;

                    // Output projection
                    let mut delta = vec![0.0f32; d];
                    mat_vec(&mut delta, o_w, &attn_out, d, qd);
                    for i in 0..d {
                        x[i] += delta[i];
                    }

                    // FFN sublayer (dense SwiGLU or sparse MoE)
                    let mut normed2 = x.clone();
                    rms_norm(&mut normed2, ffn_norm, cfg.rms_norm_eps);
                    let ffn_out = apply_ffn(ffn, &normed2, d, cfg.intermediate_size, top_k);
                    for i in 0..d {
                        x[i] += ffn_out[i];
                    }
                }

                _ => panic!("HybridPipeline: layer/state kind mismatch at layer {l}"),
            }
        }

        // Final norm + lm_head
        rms_norm(&mut x, &self.output_norm, cfg.rms_norm_eps);
        assert_eq!(logits.len(), cfg.vocab_size);
        mat_vec(logits, &self.lm_head, &x, cfg.vocab_size, d);

        self.seq_pos += 1;
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Tests — golden values from the numpy/HF reference (/tmp/jamba_ref.py +
// jamba_ref_dump.py). These validate the Jamba MoE (top-k, NO renormalization)
// and the B/C/dt-normed Mamba-1 S6 step WITHOUT needing the 54 GB knot.
// ─────────────────────────────────────────────────────────────────────────────
#[cfg(test)]
mod jamba_kernel_tests {
    use super::*;

    fn approx(a: &[f32], b: &[f32], tol: f32) {
        assert_eq!(a.len(), b.len(), "len mismatch");
        for (i, (&x, &y)) in a.iter().zip(b.iter()).enumerate() {
            assert!((x - y).abs() < tol, "elem {i}: {x} vs {y} (tol {tol})");
        }
    }

    #[test]
    fn moe_top2_no_renorm_matches_hf() {
        // hidden=3, inter=2, n_exp=4, top_k=2. Golden from numpy (HF algorithm:
        // softmax over all experts, top-2, NO renormalization, weighted SwiGLU).
        let hidden = 3usize;
        let inter = 2usize;
        let x = vec![0.5f32, -0.3, 0.8];
        let router = vec![0.1, 0.2, 0.3, 0.0, -0.1, 0.4, 0.5, 0.5, 0.5, -0.2, 0.1, 0.0];
        let experts: Vec<Expert> = (0..4)
            .map(|e| {
                let g = 0.1 * (e as f32 + 1.0);
                let u = -0.05 * (e as f32 + 1.0);
                let d = 0.2 * (e as f32 + 1.0);
                Expert {
                    gate: vec![g; inter * hidden],
                    up: vec![u; inter * hidden],
                    down: vec![d; hidden * inter],
                }
            })
            .collect();
        let out = jamba_moe_block(&x, &router, &experts, hidden, inter, 2);
        // numpy golden (experts 2 and 1 selected; weights NOT renormalized):
        approx(&out, &[-0.012225456, -0.012225456, -0.012225456], 1e-5);
    }

    #[test]
    fn jamba_s6_with_bcdt_norms_matches_hf() {
        // d_inner=2, d_state=2, dt_rank=2; one step from a zero state.
        let (di, ds, dr) = (2usize, 2usize, 2usize);
        let eps = 1e-6f32;
        let x_proj = vec![0.1, 0.2, 0.0, 0.3, 0.4, -0.1, 0.2, 0.2, -0.1, 0.1, 0.3, 0.0]; // [(dr + 2*ds), di] = [6, 2]
        let dt_proj = vec![0.5, 0.1, 0.2, 0.4]; // [di, dr]
        let dt_proj_b = vec![0.05, -0.05];
        let a_log = vec![0.0, 0.1, 0.2, -0.1]; // [di, ds] row-major
        let d_skip = vec![0.3, 0.4];
        let b_norm = vec![1.0, 1.0];
        let c_norm = vec![1.0, 1.0];
        let dt_norm = vec![1.0, 1.0];
        let xc = vec![0.6, -0.2];
        let gate = vec![0.1, 0.5];

        let mut h = vec![0.0f32; di * ds];
        let mut y = vec![0.0f32; di];
        hybrid_jamba_s6_step(
            &mut y, &xc, &mut h, &x_proj, &dt_proj, &dt_proj_b, &b_norm, &c_norm, &dt_norm, &a_log,
            &d_skip, di, ds, dr, eps,
        );
        // pre-gate golden:
        approx(&y, &[0.07031785, -0.057299148], 1e-5);
        // apply SiLU(gate) like HF (scan_output * act(gate)):
        for i in 0..di {
            y[i] *= gate[i] * sigmoid(gate[i]);
        }
        approx(&y, &[0.0036915408, -0.017833196], 1e-5);
    }

    #[test]
    fn config_layer_predicates_jamba() {
        // Build a Jamba-shaped HybridConfig and check layer typing matches HF
        // (`layers_block_type` / `layers_num_experts`).
        let cfg = HybridConfig {
            arch: "jamba".into(),
            hidden_dim: 64,
            num_layers: 32,
            vocab_size: 100,
            n_heads: 8,
            n_kv_heads: 2,
            head_dim: 8,
            rope_theta: 10000.0,
            max_seq_len: 16,
            intermediate_size: 32,
            d_state: 16,
            d_conv: 4,
            d_inner: 128,
            dt_rank: Some(256),
            num_experts: 16,
            num_experts_per_tok: 2,
            attn_layer_period: 8,
            attn_layer_offset: 4,
            expert_layer_period: 2,
            expert_layer_offset: 1,
            rms_norm_eps: 1e-6,
        };
        let attn: Vec<usize> = (0..32).filter(|&l| cfg.is_attn_layer(l)).collect();
        assert_eq!(attn, vec![4, 12, 20, 28]);
        let moe: Vec<usize> = (0..32).filter(|&l| cfg.is_moe_layer(l)).collect();
        assert_eq!(moe, (0..32).filter(|l| l % 2 == 1).collect::<Vec<_>>());
    }
}
